     1→#!/usr/bin/env node
     2→
     3→import path from "node:path";
     4→import { AGENT_IDS } from "./types.ts";
     5→import type { AgentId, CliOptions } from "./types.ts";
     6→import { loadManifest } from "./config/manifest.ts";
     7→import { AGENT_REGISTRY } from "./config/agents.ts";
     8→import { resolveHome } from "./core/resolve.ts";
     9→import { detectInstalledAgents } from "./core/detect.ts";
    10→import { planDeploy, executeDeploy } from "./core/deploy.ts";
    11→import { planRevert, executeRevert } from "./core/revert.ts";
    12→import { UserError } from "./errors.ts";
    13→
    14→const USAGE = `
    15→inception-engine - Deploy AI agent skills
    16→
    17→Usage:
    18→  inception-engine <directory> [options]
    19→  inception-engine revert <directory> [options]
    20→
    21→Options:
    22→  --dry-run        Show what would be done without doing it
    23→  --agents <list>  Comma-separated list of agent IDs to target
    24→  --verbose        Show detailed output
    25→  --debug          Show full error stack traces
    26→  --help           Show this help message
    27→
    28→Supported agents:
    29→  ${AGENT_REGISTRY.map((a) => `${a.id} (${a.displayName})`).join(", ")}
    30→`.trim();
    31→
    32→function parseArgs(argv: string[]): CliOptions {
    33→  const args = argv.slice(2);
    34→
    35→  if (args.length === 0 || args.includes("--help")) {
    36→    return { command: "help", directory: "", dryRun: false, agents: null, verbose: false, debug: false };
    37→  }
    38→
    39→  let command: "deploy" | "revert" = "deploy";
    40→  let directory = "";
    41→  let dryRun = false;
    42→  let agents: AgentId[] | null = null;
    43→  let verbose = false;
    44→  let debug = false;
    45→
    46→  let i = 0;
    47→  if (args[0] === "revert") {
    48→    command = "revert";
    49→    i = 1;
    50→  }
    51→
    52→  while (i < args.length) {
    53→    const arg = args[i]!;
    54→
    55→    if (arg === "--dry-run") {
    56→      dryRun = true;
    57→    } else if (arg === "--verbose") {
    58→      verbose = true;
    59→    } else if (arg === "--debug") {
    60→      debug = true;
    61→    } else if (arg === "--agents") {
    62→      i++;
    63→      const next = args[i];
    64→      if (!next) {
    65→        console.error("--agents requires a comma-separated list");
    66→        process.exit(1);
    67→      }
    68→      const ids = next.split(",").map((s) => s.trim());
    69→      for (const id of ids) {
    70→        if (!AGENT_IDS.includes(id as AgentId)) {
    71→          console.error(`Unknown agent: "${id}". Valid agents: ${AGENT_IDS.join(", ")}`);
    72→          process.exit(1);
    73→        }
    74→      }
    75→      agents = ids as AgentId[];
    76→    } else if (arg.startsWith("--")) {
    77→      console.error(`Unknown option: ${arg}`);
    78→      process.exit(1);
    79→    } else if (!directory) {
    80→      directory = arg;
    81→    } else {
    82→      console.error(`Unexpected argument: ${arg}`);
    83→      process.exit(1);
    84→    }
    85→    i++;
    86→  }
    87→
    88→  if (!directory) {
    89→    console.error("Missing required <directory> argument");
    90→    process.exit(1);
    91→  }
    92→
    93→  return { command, directory: path.resolve(directory), dryRun, agents, verbose, debug };
    94→}
    95→
    96→function main(): void {
    97→  const options = parseArgs(process.argv);
    98→
    99→  if (options.command === "help") {
   100→    console.log(USAGE);
   101→    process.exit(0);
   102→  }
   103→
   104→  const manifest = loadManifest(options.directory);
   105→  const home = resolveHome();
   106→
   107→  let detectedAgents: AgentId[];
   108→  if (options.agents) {
   109→    detectedAgents = options.agents;
   110→    if (options.verbose) {
   111→      console.log(`Using specified agents: ${detectedAgents.join(", ")}`);
   112→    }
   113→  } else {
   114→    detectedAgents = detectInstalledAgents(home);
   115→    if (detectedAgents.length === 0) {
   116→      console.log("No supported AI agents detected on this system.");
   117→      console.log(`Install one of: ${AGENT_REGISTRY.map((a) => a.displayName).join(", ")}`);
   118→      process.exit(0);
   119→    }
   120→    if (options.verbose) {
   121→      console.log(`Detected agents: ${detectedAgents.join(", ")}`);
   122→    }
   123→  }
   124→
   125→  const prefix = options.dryRun ? "\x1b[36m[dry-run]\x1b[0m " : "";
   126→
   127→  if (options.command === "deploy") {
   128→    const actions = planDeploy(manifest, options.directory, detectedAgents, home);
   129→    if (actions.length === 0) {
   130→      console.log("No skills to deploy for detected agents.");
   131→      return;
   132→    }
   133→
   134→    console.log(`${prefix}Deploying ${actions.length} skill(s):`);
   135→    const { succeeded, failed } = executeDeploy(actions, options.dryRun, options.verbose);
   136→
   137→    console.log();
   138→    if (failed.length > 0) {
   139→      console.log(`${succeeded} succeeded, ${failed.length} failed`);
   140→      process.exit(1);
   141→    } else {
   142→      console.log(`${succeeded} skill(s) deployed${options.dryRun ? " (dry-run)" : ""}`);
   143→    }
   144→  } else {
   145→    const actions = planRevert(manifest, detectedAgents, home);
   146→    if (actions.length === 0) {
   147→      console.log("No skills to revert for detected agents.");
   148→      return;
   149→    }
   150→
   151→    console.log(`${prefix}Reverting ${actions.length} skill(s):`);
   152→    const { succeeded, skipped } = executeRevert(actions, options.dryRun, options.verbose);
   153→
   154→    console.log();
   155→    const parts = [`${succeeded} removed`];
   156→    if (skipped > 0) parts.push(`${skipped} skipped`);
   157→    console.log(`${parts.join(", ")}${options.dryRun ? " (dry-run)" : ""}`);
   158→  }
   159→}
   160→
   161→const debugMode = process.argv.includes("--debug");
   162→
   163→try {
   164→  main();
   165→} catch (err) {
   166→  if (err instanceof UserError) {
   167→    console.error(`Error: ${err.message}`);
   168→  } else {
   169→    console.error("Unexpected error. Run with --debug for details.");
   170→  }
   171→  if (debugMode) {
   172→    console.error(err);
   173→  }
   174→  process.exit(1);
   175→}
